14	export type ScenarioResult = {
15	  results: QuoteResult[];
16	};
17	
18	const PROCESSING_FEE = 5;
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	};
25	
26	const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
27	
28	export const runScenario = (scenario: Scenario): ScenarioResult => {
29	  const results = scenario.steps.map((step) => {
30	    const itemsTotal = step.items.reduce((sum, item) => sum + basePremium(item), 0);
31	    return { premium: itemsTotal + PROCESSING_FEE };
32	  });
33	  return { results };
34	};
